args.cypher:
MATCH (aas:AssetAdministrationShell)-[:HAS_SUBMODEL]->(sm:Submodel)
WHERE EXISTS {
  MATCH (aas)-[:MANAGES_ASSET]->(asset:Asset)
  WHERE (asset:Asset OR aas) CONTAINS 'Hall 4' OR aas.idShort CONTAINS 'Hall 4' OR aas.idShort CONTAINS 'Hall4' OR aas.idShort CONTAINS 'hall4'
}
RETURN aas.idShort, aas.id, aas.category, aas.kind
